    public partial class DepartmentGroupService : BaseService<DepartmentGroup>, IDepartmentGroupService
    {
        public DepartmentGroupService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<DepartmentGroup> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<DepartmentGroup>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Groups),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<DepartmentGroup>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<DepartmentGroup>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Groups.Name.Contains(search.Name))
                     && x.DeskDepartmentId == search.RefId.Value,
                include: i => i.Include(x => x.Groups),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Groups.Name", ascending: !search.IsDescend);
        }
    }
